var e=[{id:`L3_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`안젤라 씨! 어디 있어요!`,JPN:`アンジェラさん！　どこですか！`,ENG:`Angela! Where are you?`,TWN:`安潔拉小姐！你在哪！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`안젤라 씨!`,JPN:`アンジェラさん！`,ENG:`Angela!`,TWN:`安潔拉小姐！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`SOLDIER_GRONIA_NULL_NULL`,text:{KOREA:`크헉……!`,JPN:`くはっ……！`,ENG:`Hngh!?`,TWN:`唔……！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SOLDIER_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`MORS_SHADOW_ARMOR_NULL`,text:{KOREA:`여인의 소재를 말하라. 그리하면 목숨을 해치지 않으리니.`,JPN:`女の居場所を話せ。そうしたら命は助けてやろう。`,ENG:`Name the whereabouts of the woman. So your life may be spared.`,TWN:`說出女人在哪裡，我就饒你不死。`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`MORS_SHADOW_ARMOR_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SOLDIER_GRONIA_NULL_NULL`,text:{KOREA:`힉……! 히익……!`,JPN:`ひ……！　ひいっ……！`,ENG:`E-eeek!`,TWN:`嗚……！嗚嗚……！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SOLDIER_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SOLDIER_GRONIA_NULL_NULL`,text:{KOREA:`지, 지하실! 지하실에 가뒀다는 얘길 들었습니다!`,JPN:`ち、地下室！　地下室に閉じ込めたって聞きました！`,ENG:`B-basement! I heard she was locked in the basement!`,TWN:`她…她在地下室！我聽說她被關在地下室裡！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SOLDIER_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SOLDIER_GRONIA_NULL_NULL`,text:{KOREA:`그것뿐이에요! 제발 살려 주십시오!`,JPN:`それだけです！　どうか助けてください！`,ENG:`That’s all I know! S-s-pare me!`,TWN:`我就只知道這些！拜託別殺我！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SOLDIER_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MORS_SHADOW_ARMOR_NULL`,text:{KOREA:`……지하실인가. 알겠다.`,JPN:`……地下室か。承知した。`,ENG:`...The basement. Understood.`,TWN:`……在地下室嗎？好。`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`MORS_SHADOW_ARMOR_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:null,text:{KOREA:`무기가 전혀 통하지 않아! 지원을 요청해!`,JPN:`武器がまったく通じない！　支援を呼べ！`,ENG:`Weapons aren’t working at all! Call for backup!`,TWN:`武器對她根本沒有效！快請求支援！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`처, 천장이 무너진다!! 도망쳐!`,JPN:`て、天井が崩れる！！　逃げろ！`,ENG:`The c-ceiling is collapsing!! Run away!`,TWN:`天…天花板要塌啦！！大家快逃！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`…`,TWN:`……`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`저, 정신 나간 녀석인 줄은 알았지만……. 정부군이랑 혼자 전쟁이라도 벌이려는 건가?`,JPN:`しょ、正気じゃない奴なのはわかってたけど……一人で政府軍と戦争でも起こそうとしてるの？`,ENG:`I already knew she was crazy but... Is she really going to take on the entire government alone?`,TWN:`我…我還以為她只是精神不正常……結果她是打算單獨和政府軍開戰嗎？`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`아니, 이럴 때가 아니지. 레버넌트 씨가 저 자랑 마주쳤다간…….`,JPN:`いや、こうしている場合じゃない。レヴナントさんがあれと出くわしたら……`,ENG:`No, this isn’t the time for that. I can’t let Revenant run into that monster...`,TWN:`不對，現在不是想這些的時候，萬一我錯過亡靈小姐……`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`중사……? 여기서 뭐 하고 있어?`,JPN:`軍曹……？　ここで何してるの？`,ENG:`Sergeant...? What are you doing here?`,TWN:`中士……？你在這裡做什麼？`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`레버넌트 씨?!`,JPN:`レヴナントさん！？`,ENG:`Revenant?!`,TWN:`亡靈小姐？！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L34_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`정말 레버넌트 씨 맞아요? 지하실에 갇혀 있던 거 아니었어요?`,JPN:`本当にレヴナントさんなんですか？　地下室に閉じ込められてたんじゃなかったんですか？`,ENG:`Is that really you, Revenant? Weren’t you being kept in the basement?`,TWN:`真的是你？你不是被關在地下室嗎？`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`}}}}];export{e as default};